#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
  if (argc != 3) {
    printf("Xeta: Tam olaraq 2 eded daxil edin!\n");
    printf("Numune: ./program 5 3\n");
    return 1;
  }
  int num1 = atoi(argv[1]);
  int num2 = atoi(argv[2]);
  printf("Cem: %d\n", num1 + num2);
  return 0;
}
