#include <stdio.h>

int main(int argc, char *argv[]) {
  if (argc != 2) {
    printf("Xeta: Fayl adi daxil edin!\n");
    printf("Numune: ./program output.txt\n");
    return 1;
  }
  FILE* file = fopen(argv[1], "w");
  if (file == NULL) {
    printf("Fayl acilmadi!\n");
    return 1;
  }
  fprintf(file, "Salam, Dunya!\n");
  fclose(file);
  printf("Fayla yazildi: %s\n", argv[1]);
  return 0;
}
// Komanda xətti: ./program output.txt
// Output:
// Fayla yazildi: output.txt
// (output.txt faylına yazılır: Salam, Dunya!)

