    printf("Error: Please provide a file name!\n");
    printf("Example: ./program output.txt\n");
    return 1;
  }
  FILE* file = fopen(argv[1], "w");
  if (file == NULL) {
    printf("File could not be opened!\n");
    return 1;
  }
